import{_ as t,c as o,o as a,al as s}from"./chunks/framework.DM883ANZ.js";const p=JSON.parse('{"title":"路由","description":"路由 — MAVLink message, enum and command reference.","frontmatter":{"head":[["meta",{"property":"og:title","content":"路由"}],["meta",{"property":"og:description","content":"路由 — MAVLink message, enum and command reference."}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:url","content":"https://mavlink.io/zh/guide/routing.html"}],["link",{"rel":"canonical","href":"https://mavlink.io/zh/guide/routing.html"}]]},"headers":[],"relativePath":"zh/guide/routing.md","filePath":"zh/guide/routing.md","lastUpdated":1783983958000}'),n={name:"zh/guide/routing.md"};function r(i,e,c,d,l,m){return a(),o("div",null,[...e[0]||(e[0]=[s('<h1 id="路由" tabindex="-1">路由 <a class="header-anchor" href="#路由" aria-label="Permalink to &quot;路由&quot;">​</a></h1><p>这个主题解释了如何由 MAVLink 系统路由信息。</p><h2 id="综述" tabindex="-1">综述 <a class="header-anchor" href="#综述" aria-label="Permalink to &quot;综述&quot;">​</a></h2><p>一个 MAVLINK 网络由多种系统组成（无人机、地面站、天线追踪器等），这些系统可能由一个或多个组件（自动试验、相机、服务器等）组成。</p><p>Each system has a network-unique <em>system ID</em>, and each component has a system-unique <em>component ID</em> that can be used for addressing/routing. Both are values between 1 and 255.</p><p>消息可用于所有系统、特定系统、系统中的所有组件或系统内的特定组件。 协议界定了在报文有效载荷中能够(可选) 指定的两个8位字段，以表明发送/路由。 If the IDs are omitted or set to zero then the message is considered a <em>broadcast</em> (intended for all systems/components).</p><ul><li><code>target_system</code>: System that should execute the command</li><li><code>target_component</code>: Component that should execute the command (requires <code>target_system</code>).</li></ul><p>MAVLink components are expected to process messages that have a matching system/component ID and broadcast messages. They are expected to route/resend messages that are intended for other (or all) recipients to other active channels (i.e. MAVLink systems may be connected across different transports, connected by a MAVLink system that routes the messages). 广播消息已转发给所有尚未看到消息的通道。 Addressed messages are resent on a new channel <em>iff</em> the system has previously seen a message from the target on that channel (messages are not resent if the addressee is not known or is on the original/incoming channel).</p><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Forwarded messages must not be changed/repackaged by the forwarding system (the original message is passed to the new link).</p></div><div class="info custom-block"><p class="custom-block-title">INFO</p><p>Systems should, where possible, forward messages according to the routing rules <em>even if they are unable to process them</em> (e.g. signed messages that cannot be authenticated). Messages that are not supported/understood by the library should be forwarded as though they were broadcast messages (in this case the target system/component IDs cannot be read).</p></div><h2 id="id-allocation" tabindex="-1">ID allocation <a class="header-anchor" href="#id-allocation" aria-label="Permalink to &quot;ID allocation&quot;">​</a></h2><p>MAVLink does not provide mechanisms to automate allocation of system and component IDs. Instead these are manually allocated by the system integrator.</p><p>In order to reduce the chance of collisions (by convention):</p><ul><li>Autopilots on a MAVLink network are allocated sequentially increasing system IDs from <code>1</code> (<code>1</code> is usually the default autopilot system ID).</li><li>GCS and MAVLink developer APIs are allocated sequentially decreasing system IDs, starting from <code>255</code>. Note that GCS will usually, but not always, have an ID in the upper range.</li><li>Components can be allocated any unused ID in the range. Components usually have a default value based on their type, as mapped by <a href="./../messages/common.html#MAV_COMPONENT">MAV_COMPONENT</a>.</li></ul><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Code <strong>must not assume</strong> from the component ID that it knows the type of the component. The type of a component must be determined from its <a href="./../messages/common.html#MAV_TYPE">MAV_TYPE</a></p></div><p>Components should expose mechanisms to set their system and component IDs. Commonly a component may be configured to discover its system ID on boot by latching the system ID of the first autopilot <a href="./../messages/common.html#HEARTBEAT">HEARTBEAT</a> that it discovers.</p><h2 id="路由详细信息" tabindex="-1">路由详细信息 <a class="header-anchor" href="#路由详细信息" aria-label="Permalink to &quot;路由详细信息&quot;">​</a></h2><p>A component should attempt to process a message locally if any of these conditions hold:</p><ul><li>The <code>target_system</code> field is omitted or has value <code>0</code> (&quot;network broadcast&quot;).</li><li>The <code>target_system</code> matches its system ID and the <code>target_component</code> field is omitted or has value <code>0</code> (&quot;system broadcast&quot;).</li><li>The <code>target_system</code> and <code>target_component</code> matches its system and component IDs.</li></ul><p>Components that have multiple channels should forward a message to other channels if any of these conditions hold:</p><ul><li>It is a network broadcast message (<code>target_system</code> field omitted or zero).</li><li>The <code>target_system</code> does not match the system ID <em>and</em> the component has previously seen a message from <code>target_system</code> on the link.</li><li>The <code>target_system</code> matches its system ID and has a <code>target_component</code> field, and the component has seen a message from the <code>target_system</code>/<code>target_component</code> combination on the link.</li></ul><div class="info custom-block"><p class="custom-block-title">INFO</p><p>Non-broadcast messages must only be forwarded to channels from which the component has previously received a message from the target system/component.</p></div><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Components should also check for <code>SYSTEM_TIME</code> messages with a decrease in <code>time_boot_ms</code>, as this indicates that the system has rebooted. In this case it should clear stored routing information (and might perform other actions that are useful following a reboot - e.g. re-fetching parameters and home position etc.).</p></div><h2 id="库支持" tabindex="-1">库支持 <a class="header-anchor" href="#库支持" aria-label="Permalink to &quot;库支持&quot;">​</a></h2><h3 id="c-库-mavgen" tabindex="-1">C 库 (mavgen) <a class="header-anchor" href="#c-库-mavgen" aria-label="Permalink to &quot;C 库 (mavgen)&quot;">​</a></h3><p>The generated code for the MAVLink v1 C Library has no specific support for routing or working with <code>target_system</code> and <code>target_component</code>. To extract this information you will need to use the normal methods provided for reading payload fields, and match on the field names.</p><p>The MAVLink v2 generator for the C library has been updated to make it easier to get the destination system and component ID from the payload (when these are assigned). Specifically, the <code>mavlink_msg_entry_t</code> structure contains flags to tell you if the message contains target system/component information (<code>FLAG_HAVE_TARGET_SYSTEM</code>, <code>FLAG_HAVE_TARGET_COMPONENT</code>) and offsets into the payload that you can use to get these IDs (<code>target_system_ofs</code> and <code>target_component_ofs</code>, respectively). The MAVLink helper method <code>const mavlink_msg_entry_t*</code> <a href="https://github.com/mavlink/c_library_v2/blob/master/mavlink_helpers.h" target="_blank" rel="noreferrer"><code>mavlink_get_msg_entry(uint32_t msgid)</code></a> can be used to get this structure from the message ID.</p><h2 id="mavlink-2-路由" tabindex="-1">MAVLink 2 路由 <a class="header-anchor" href="#mavlink-2-路由" aria-label="Permalink to &quot;MAVLink 2 路由&quot;">​</a></h2><p>Unsigned MAVLink 2 packets are routed in the same way as MAVLink 1 packets.</p><h2 id="routing_signed_packets" tabindex="-1">Routing Signed Packets <a class="header-anchor" href="#routing_signed_packets" aria-label="Permalink to &quot;Routing Signed Packets {#routing_signed_packets}&quot;">​</a></h2><p>Signed packets should be routed in the same way as any other packet.</p><p>In particular, a routing system should:</p><ul><li>不以任何方式更改电文(包括替换原始签字)。</li><li>即使不能被验证(甚至理解)，因此不能在当地加以处理，也按照正常规则提交信息。</li></ul><h2 id="路由接口" tabindex="-1">路由接口 <a class="header-anchor" href="#路由接口" aria-label="Permalink to &quot;路由接口&quot;">​</a></h2><p>The <a href="https://github.com/mavlink-router/mavlink-router" target="_blank" rel="noreferrer">MAVLink Router</a> can be used to mix-and-match different IP protocols with serial ports in order to route MAVLink traffic.</p><h2 id="更多信息" tabindex="-1">更多信息 <a class="header-anchor" href="#更多信息" aria-label="Permalink to &quot;更多信息&quot;">​</a></h2><ul><li><a href="http://ardupilot.org/dev/docs/mavlink-routing-in-ardupilot.html" target="_blank" rel="noreferrer">MAVLink Routing in ArduPilot</a> (ArduPilot DevGuide)</li></ul>',37)])])}const u=t(n,[["render",r]]);export{p as __pageData,u as default};
